app.post('/authorize/consent', (req, res) => {
  const { client_id, redirect_uri, scope, state, consent } = req.body;

  const client = validateClient(client_id);
  if (!client || !validateRedirectUri(client, redirect_uri)) {
    return res.status(400).send('Invalid request');
  }

  const parsedUrl = url.parse(redirect_uri, true);
  delete parsedUrl.search;

  if (consent !== 'approve') {
    parsedUrl.query.error = 'access_denied';
    parsedUrl.query.error_description = 'User denied authorization';
    if (state) parsedUrl.query.state = state;
    return res.redirect(url.format(parsedUrl));
  }

  const code = generateRandomString();
  const expiresAt = Date.now() + 600000;

  authorizationCodes.set(code, {
    clientId: client_id,
    redirectUri: redirect_uri,
    scope: scope || '',
    expiresAt: expiresAt,
    userId: 'user123'
  });

  parsedUrl.query.code = code;
  if (state) parsedUrl.query.state = state;

  res.redirect(url.format(parsedUrl));
});

app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret } = req.body;

  let authClientId = client_id;
  let authClientSecret = client_secret;

  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const base64Credentials = authHeader.slice(6);
    const credentials = Buffer.from(base64Credentials, 'base64').toString('utf-8');
    const [headerClientId, headerClientSecret] = credentials.split(':');
    authClientId = headerClientId;
    authClientSecret = headerClientSecret;
  }

  if (!authClientId || !authClientSecret) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Client authentication failed' });
  }

  const client = validateClient(authClientId, authClientSecret);
  if (!client) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Client authentication failed' });
  }

  if (grant_type !== 'authorization_code') {
    return res.status(400).json({ error: 'unsupported_grant_type', error_description: 'Only authorization_code grant type is supported' });
  }

  if (!code) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing authorization code' });
  }

  const authCode = authorizationCodes.get(code);
  if (!authCode) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid authorization code' });
  }

  if (authCode.expiresAt < Date.now()) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code expired' });
  }

  if (authCode.clientId !== authClientId) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code was issued to another client' });
  }

  if (authCode.redirectUri !== redirect_uri) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Redirect URI mismatch' });
  }

  authorizationCodes.delete(code);

  const accessToken = generateRandomString();
  const refreshToken = generateRandomString();
  const expiresIn = 3600;

  accessTokens.set(accessToken, {
    clientId: authClientId,
    userId: authCode.userId,
    scope: authCode.scope,
    expiresAt: Date.now() + expiresIn * 1000
  });

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: expiresIn,
    refresh_token: refreshToken,
    scope: authCode.scope
  });
});

app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token' });
  }

  const token = authHeader.slice(7);
  const tokenData = accessTokens.get(token);

  if (!tokenData) {
    return res.status(401).json({ error: 'invalid_token' });
  }

  if (tokenData.expiresAt < Date.now()) {
    accessTokens.delete(token);
    return res.status(401).json({ error: 'token_expired' });
  }

  res.json({
    sub: tokenData.userId,
    name: 'John Doe',
    email: 'john@example.com'
  });
});

